The code has bug and does not give expected result. This is my simpler approach - Sweep Line algorithm using Event Processing.

public Map<Integer, Integer> assignCars(int[][] requests) {
    List<int[]> events = new ArrayList<>();
    for (int[] req : requests) {
        // [time, type, id] -> type: 0 for Drop, 1 for Pickup
        events.add(new int[]{req[1], 1, req[0]}); // Pickup
        events.add(new int[]{req[2], 0, req[0]}); // Drop
    }

    // Sort by time, then type (Drop before Pickup)
    events.sort((a, b) -> a[0] == b[0] ? a[1] - b[1] : a[0] - b[0]);

    Stack<Integer> idlePool = new Stack<>();
    Map<Integer, Integer> assignment = new HashMap<>();
    int nextNewCarId = 0;

    for (int[] event : events) {
        int type = event[1];
        int reqId = event[2];

        if (type == 1) { // Pickup
            if (!idlePool.isEmpty()) {
                assignment.put(reqId, idlePool.pop());
            } else {
                assignment.put(reqId, nextNewCarId++);
            }
        } else { // Drop
            idlePool.push(assignment.get(reqId));
        }
    }
    return assignment;
}

