def assignCars(n: int, requests: List[List[int]]) -> List[List[int]]:
    requests.sort(key = lambda x : x[1]) # sort based on pickupTime
    ans = []
    available = []
    busy = []
    for i in range(n):
        heapq.heappush(available, i)

    for rID, pickupTime, returnTime in requests:
        while busy and busy[0][0] <= pickupTime:
            _, carID = heapq.heappop(busy)
            heapq.heappush(available, carID)

        if available:
            carId = heapq.heappop(available)
            ans.append([rID, carId])
            heapq.heappush(busy, (returnTime, carId))
        else:
            return []

    return ans

