import heapq

def assignCars(N, requests):
    # Sort requests by pickup time
    requests.sort(key=lambda x: x['pickup'])

    result = []
    heap = []  # (nextAvailableTime, carId)
    car_count = 0

    for req in requests:
        # Reuse the earliest available car with smallest carId
        if heap and heap[0][0] <= req['pickup']:
            next_time, car_id = heapq.heappop(heap)
        else:
            car_id = car_count
            car_count += 1

        result.append({'requestId': req['id'], 'carId': car_id})
        heapq.heappush(heap, (req['return'], car_id))

    return result

